class MyRange:
    def __init__(self, start, stop=None, step=1):
        if stop is None:
            self.start = 0
            self.stop = start
        else:
            self.start = start
            self.stop = stop
        self.step = step

        if self.step == 0:
            raise ValueError("MyRange() arg 3 must not be zero")

    def __iter__(self):
        current = self.start
        if self.step > 0:
            while current < self.stop:
                yield current
                current += self.step
        else: # self.step < 0
            while current > self.stop:
                yield current
                current += self.step

